PyDoc_STRVAR(__pyx_doc_24unicorn_binance_rest_api_7manager_21BinanceRestApiManager_230get_margin_repay_details, "\n        Query repay record\n\n        txId or startTime must be sent. txId takes precedence.\n\n        https://binance-docs.github.io/apidocs/spot/en/#query-repay-record-user_data\n\n        :param asset: required\n        :type asset: str\n        :param isolatedSymbol: isolated symbol (if querying isolated margin)\n        :type isolatedSymbol: str\n        :param txId: the tranId in of the created loan\n        :type txId: str\n        :param startTime:\n        :type startTime: str\n        :param endTime: Used to uniquely identify this cancel. Automatically generated by default.\n        :type endTime: str\n        :param current: Currently querying page. Start from 1. Default:1\n        :type current: str\n        :param size: Default:10 Max:100\n        :type size: int\n        :param recvWindow: the number of milliseconds the request is valid for\n        :type recvWindow: int\n\n        :return: API response\n\n        .. code-block:: python\n\n            {\n                \"rows\": [\n                    {\n                        //Total amount repaid\n                        \"amount\": \"14.00000000\",\n                        \"asset\": \"BNB\",\n                        //Interest repaid\n                        \"interest\": \"0.01866667\",\n                        //Principal repaid\n                        \"principal\": \"13.98133333\", # one of PENDING (pending to execution), CONFIRMED (successfully\n                                                    # loaned), FAILED (execution failed, nothing happened to your\n                                                    # account);\n                        \"status\": \"CONFIRMED\",\n                        \"timestamp\": 1563438204000,\n                        \"txId\": 2970933056\n                    }\n                ],\n                \"total\": 1\n            }\n\n        :raises: BinanceRequestException, BinanceAPIException\n\n        ");
